import React, { useState } from "react";

function OCSVM() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule4 = async () => {
    setLoading(true);

    try {
      const res = await fetch("http://127.0.0.1:5000/module4");
      const data = await res.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Backend error");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 4: OCSVM Anomaly Detection</h2>

      <button onClick={runModule4}>Run Module 4</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>

          <h3>Total Test Samples: {result.test_size}</h3>
          <h3>Accuracy: {(result.accuracy * 100).toFixed(2)}%</h3>

          <h3>Prediction Table</h3>

          <div style={{
            height: "500px",
            overflowY: "scroll",
            border: "1px solid black"
          }}>
            <table border="1" width="100%">
              <thead>
                <tr>
                  <th>Index</th>
                  <th>Actual</th>
                  <th>Predicted</th>
                </tr>
              </thead>

              <tbody>
                {result.predictions.map((pred, index) => (
                  <tr key={index}>
                    <td>{index}</td>
                    <td>{result.actual[index]}</td>
                    <td>{pred}</td>
                  </tr>
                ))}
              </tbody>

            </table>
          </div>

        </div>
      )}
    </div>
  );
}

export default OCSVM;
